export function getBlogBySlug(slug) {
  return blogs.find((b) => b.slug === slug) ?? null;
}

export function getRelatedBlogs(currentSlug, count = 3) {
  const current = getBlogBySlug(currentSlug);
  if (!current) return [];
  const same = blogs.filter(
    (b) => b.slug !== currentSlug && b.category?.slug === current.category?.slug
  );
  if (same.length >= count) return same.slice(0, count);
  const others = blogs.filter(
    (b) => b.slug !== currentSlug && b.category?.slug !== current.category?.slug
  );
  return [...same, ...others].slice(0, count);
}
